#include <stdio.h>
#include <stdlib.h>
#include <mpi.h>
#include <time.h>
#include <math.h>

#define MASTER 0
#define TAG_TASK 1
#define TAG_RESULT 2
#define TAG_DONE 3

/* Structure to hold task data */
typedef struct {
 int task_id;
 double compute_amount; // Simulates varying workload
} Task;

/* Simulate computation work */
double simulate_work(double amount) {
 double result = 0;
 for (int i = 0; i < (int)(amount * 100000); i++) {
 result += sin(i) * cos(i);
 }
 return result;
}

/* Static Load Balancing: Divide work equally before execution */
void static_load_balance(int num_tasks, int num_procs, double *task_times, int *assignments) {
 int tasks_per_proc = num_tasks / num_procs;
 int remainder = num_tasks % num_procs;

 int current_task = 0;
 for (int p = 0; p < num_procs; p++) {
 int my_tasks = tasks_per_proc + (p < remainder ? 1 : 0);
 assignments[p] = my_tasks;

 for (int t = 0; t < my_tasks; t++) {
 task_times[current_task++] = 1.0 + (rand() % 100) / 100.0; // Varying load
 }
 }
}

/* Dynamic Load Balancing: Master assigns tasks on-demand */
void dynamic_load_balance(int num_tasks, int num_procs, MPI_Status *status) {
 int num_procs_actual = num_procs - 1; // Exclude master
 int tasks_sent = 0;
 int tasks_completed = 0;
 double result;

 // Phase 1: Send initial tasks (at least one per worker)
 for (int dest = 1; dest <= num_procs_actual && dest <= num_tasks; dest++) {
 MPI_Send(&tasks_sent, 1, MPI_INT, dest, TAG_TASK, MPI_COMM_WORLD);
 tasks_sent++;
 }

 // Phase 2: Receive results and send new tasks
 while (tasks_completed < num_tasks) {
 MPI_Recv(&result, 1, MPI_DOUBLE, MPI_ANY_SOURCE, TAG_RESULT, MPI_COMM_WORLD, status);
 tasks_completed++;

 if (tasks_sent < num_tasks) {
 MPI_Send(&tasks_sent, 1, MPI_INT, status->MPI_SOURCE, TAG_TASK, MPI_COMM_WORLD);
 tasks_sent++;
 } else {
 // Send termination signal
 int done = -1;
 MPI_Send(&done, 1, MPI_INT, status->MPI_SOURCE, TAG_DONE, MPI_COMM_WORLD);
 }
 }

 // Wait for all workers to finish
 for (int dest = 1; dest <= num_procs_actual; dest++) {
 MPI_Recv(&result, 1, MPI_DOUBLE, dest, TAG_RESULT, MPI_COMM_WORLD, status);
 }
}

/* Worker process for dynamic load balancing */
void worker_process_dynamic() {
 MPI_Status status;
 int task_id;
 double result;

 while (1) {
 MPI_Recv(&task_id, 1, MPI_INT, MASTER, MPI_ANY_TAG, MPI_COMM_WORLD, &status);

 if (status.MPI_TAG == TAG_DONE) {
 break;
 }

 // Simulate varying workload (irregular problem)
 double work_amount = 1.0 + (rand() % 100) / 10.0;
 result = simulate_work(work_amount);

 // Send result back to master
 MPI_Send(&result, 1, MPI_DOUBLE, MASTER, TAG_RESULT, MPI_COMM_WORLD);
 }
}

/* Compute function for static parallel execution */
void compute_static_portion(int my_start, int my_count) {
 double result = 0;
 for (int i = my_start; i < my_start + my_count; i++) {
 result += simulate_work(1.0 + (i % 100) / 100.0);
 }
}

int main(int argc, char *argv[]) {
 int rank, num_procs;
 double start_time, end_time, static_time, dynamic_time;
 int num_tasks = 1000;

 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &num_procs);

 srand(time(NULL) + rank);

 if (rank == MASTER) {
 printf("=== MPI Performance: Static vs Dynamic Load Balancing ===\n");
 printf("Number of processors: %d\n", num_procs);
 printf("Number of tasks: %d\n\n", num_tasks);

 // Static Load Balancing Test
 printf("--- Static Load Balancing ---\n");
 start_time = MPI_Wtime();

 int *displacements = malloc(num_procs * sizeof(int));
 int *sendcounts = malloc(num_procs * sizeof(int));
 double *all_task_times = malloc(num_tasks * sizeof(double));

 // Distribute tasks equally
 int base_count = num_tasks / num_procs;
 int remainder = num_tasks % num_procs;

 for (int i = 0; i < num_procs; i++) {
 sendcounts[i] = base_count + (i < remainder ? 1 : 0);
 displacements[i] = i * base_count + (i < remainder ? i : remainder);
 }

 // Each process computes its portion
 MPI_Scatterv(all_task_times, sendcounts, displacements, MPI_DOUBLE,
 MPI_IN_PLACE, 0, MPI_DOUBLE, MASTER, MPI_COMM_WORLD);

 // Compute (simulated)
 for (int i = 0; i < sendcounts[rank]; i++) {
 simulate_work(1.0 + (rand() % 100) / 100.0);
 }

 MPI_Barrier(MPI_COMM_WORLD);
 end_time = MPI_Wtime();
 static_time = end_time - start_time;

 printf("Static load balance time: %.4f seconds\n", static_time);

 // Dynamic Load Balancing Test
 printf("\n--- Dynamic Load Balancing ---\n");
 start_time = MPI_Wtime();
 dynamic_load_balance(num_tasks, num_procs, &status);
 end_time = MPI_Wtime();
 dynamic_time = end_time - start_time;

 printf("Dynamic load balance time: %.4f seconds\n", dynamic_time);

 // Analysis
 printf("\n=== Performance Analysis ===\n");
 if (dynamic_time < static_time) {
 printf("Dynamic load balancing is %.2f%% faster\n", 
 (static_time - dynamic_time) / static_time * 100);
 } else {
 printf("Static load balancing performed better for this workload\n");
 }

 free(displacements);
 free(sendcounts);
 free(all_task_times);

 } else {
 // Worker processes
 // For static: participate in scatter and computation
 int base_count = num_tasks / num_procs;
 int my_count = base_count + (rank < (num_tasks % num_procs) ? 1 : 0);

 // Do computation
 for (int i = 0; i < my_count; i++) {
 simulate_work(1.0 + (rand() % 100) / 100.0);
 }

 MPI_Barrier(MPI_COMM_WORLD);

 // For dynamic: run worker loop
 worker_process_dynamic();
 }

 MPI_Finalize();
 return 0;
}
